element.CSSource:
if (i_arg1.RowType != typeof(IpV4V6Range))
 return;
if (i_arg1.FieldName != "vlanRange" && i_arg1.FieldName != "macRange" && i_arg1.FieldName != "atmRange" && i_arg1.FieldName != "pvcRange")
 return;
if (!(m_group.stack is EthernetPlugin) && !(m_group.stack is ATMPlugin))
 return;
if (!(i_arg1.ColumnEditor is DevExpress.XtraEditors.Repository.RepositoryItemLookUpEdit))
 return;

if(m_group.stack is EthernetPlugin)
{
    EthernetPlugin plugin=(EthernetPlugin)m_group.stack;
    DevExpress.XtraEditors.Repository.RepositoryItemLookUpEdit edit=(DevExpress.XtraEditors.Repository.RepositoryItemLookUpEdit)i_arg1.ColumnEditor;
    edit.DisplayMember = "name";
    edit.ValueMember   = "$$OBJECT$$";
    if (i_arg1.FieldName =="vlanRange") 
    {
        edit.DataSource=new DynamicDataList(plugin.vlanRangeList);
    }
    else if (i_arg1.FieldName =="macRange") 
    {
        edit.DataSource=new DynamicDataList(plugin.macRangeList);
    }
    edit.Columns.Clear();
    edit.Columns.Add(new DevExpress.XtraEditors.Controls.LookUpColumnInfo("name"));
}
else if(m_group.stack is ATMPlugin)
{
    ATMPlugin plugin=(ATMPlugin)m_group.stack;
    DevExpress.XtraEditors.Repository.RepositoryItemLookUpEdit edit=(DevExpress.XtraEditors.Repository.RepositoryItemLookUpEdit)i_arg1.ColumnEditor;
    edit.DisplayMember = "name";
    edit.ValueMember   = "$$OBJECT$$";
    if (i_arg1.FieldName =="atmRange") 
    {
        edit.DataSource=new DynamicDataList(plugin.atmRangeList);
    }
    else if (i_arg1.FieldName =="pvcRange") 
    {
        edit.DataSource=new DynamicDataList(plugin.pvcRangeList);
    }
    edit.Columns.Clear();
    edit.Columns.Add(new DevExpress.XtraEditors.Controls.LookUpColumnInfo("name"));
}

if (!i_arg1.ColumnType.Equals(typeof(aptixia.clcs.MacRange)) &&
    !i_arg1.ColumnType.Equals(typeof(aptixia.clcs.AtmRange)) &&
    !i_arg1.ColumnType.Equals(typeof(aptixia.clcs.PvcRange)) &&
    !i_arg1.ColumnType.Equals(typeof(aptixia.clcs.VlanIdRange)))
    return;

if (i_arg1.Data.ToString() == "") return;

IpV4V6Range range = (IpV4V6Range)m_form.rangeListGrid.SelectedRow;

if (range == null) 
  return;

if(m_group.stack is EthernetPlugin)
{
    EthernetPlugin eth = m_group.stack as EthernetPlugin;

    if (eth == null) 
        return;
/*
    bool success = false;
    range.AutoGenerateMacRange(true, ref success);
    if(success)
    {
        range.macRange.name = i_arg1.Data.ToString();

        eth._Context.SyncAll();
        range._Context.SyncAll();

        m_object._Context.InvalidateAll();
        m_form.rangeListGrid.UpdateCurrentRow();
    }*/

    if(i_arg1.ColumnType.Equals(typeof(aptixia.clcs.MacRange)))
    {
        MacRange mac=MacRange._Create(m_object._Context);
        mac.name = i_arg1.Data.ToString();
        range.macRange=mac;
        eth.macRangeList.Add(mac);
        eth._Context.SyncAll();
        range._Context.SyncAll();
    }
    else if(i_arg1.ColumnType.Equals(typeof(aptixia.clcs.VlanIdRange)))
    {
        VlanIdRange vlan=VlanIdRange._Create(m_object._Context);
        vlan.name = i_arg1.Data.ToString();
        range.vlanRange=vlan;
        eth.vlanRangeList.Add(vlan);
        eth._Context.SyncAll();
        range._Context.SyncAll();
    }
}
else if(m_group.stack is ATMPlugin)
{
    ATMPlugin atm = m_group.stack as ATMPlugin;

    if (atm == null) 
        return;

    if(i_arg1.ColumnType.Equals(typeof(aptixia.clcs.AtmRange)))
    {
/*        bool success = false;
        range.AutoGenerateAtmRange(ref success);
        if(success)
        {
            range.atmRange.name = i_arg1.Data.ToString();
            m_object._Context.InvalidateAll();
            m_form.rangeListGrid.UpdateCurrentRow();
        }*/
        AtmRange atmRange = AtmRange._Create(m_object._Context);
        atmRange.name = i_arg1.Data.ToString();
        range.atmRange = atmRange;
        atm.atmRangeList.Add(atmRange);
        atm._Context.SyncAll();
        range._Context.SyncAll();
    }
    else if(i_arg1.ColumnType.Equals(typeof(aptixia.clcs.PvcRange)))
    {
/*        bool success = false;
        range.AutoGeneratePvcRange(ref success);
        if(success)
        {
            range.pvcRange.name = i_arg1.Data.ToString();
            m_object._Context.InvalidateAll();
            m_form.rangeListGrid.UpdateCurrentRow();
        }*/
        PvcRange pvcRange = PvcRange._Create(m_object._Context);
        pvcRange.name = i_arg1.Data.ToString();
        range.pvcRange = pvcRange;
        atm.pvcRangeList.Add(pvcRange);
        atm._Context.SyncAll();
        range._Context.SyncAll();
    }
}

aptixia.sm.DynamicGridControl control = (aptixia.sm.DynamicGridControl)i_arg0;
aptixia.sm.DynamicGridControlEvent ev = i_arg1;
int index = ev.RowIndex;
IpV4V6Range newrange = (IpV4V6Range)control.Collection[index];
newrange.name += newrange._ObjectId.ToString();

if (index > 0)
{
	IpV4V6Range priorrange = (IpV4V6Range)control.Collection[index-1];
	INetAddress workAddress = AddressFactory.CreateAddress(priorrange.ipAddress);
	priorrange.ipAddress = workAddress.AsString(); //reformat working this row's address
	priorrange.ipType = workAddress.TypeString(); //make sure address type is set properly
	INetAddress nextAddress = workAddress.NextBaseAddress((ulong)priorrange.prefix).Add(1);
	newrange.ipAddress = nextAddress.AsString();
	newrange.ipType = priorrange.ipType;

	if (priorrange.prefix < (long)workAddress.MinSlashMask())
		priorrange.prefix = (long)workAddress.DefaultSlashMask();

	newrange.prefix = priorrange.prefix;
	newrange.incrementBy = AddressFactory.CreateAddress(0, 1, workAddress.TypeString()).AsString();
	newrange.gatewayAddress = nextAddress.DefaultGateway((ulong)newrange.prefix).AsString();

	newrange.count = 1; //(long)nextAddress.HostCountInMask((ulong)newrange.prefix);

	/*
	//limit count to 0x7fffffff. Column will overflow otherwise
	if (newrange.count > 0x7fffffff)
	newrange.count = 0x7fffffff;

	//if column HAS overlowed, set to 0x7fffffff
	if (newrange.count < 0)
	newrange.count = 0x7fffffff;

	//if the count is greater than the mask can contain, limit it
	if (newrange.count > (long)workAddress.HostCountInMask((ulong)newrange.prefix))
	newrange.count = (long)workAddress.HostCountInMask((ulong)newrange.prefix);
	*/
}

if ( newrange.ipType == "IPv6")
newrange.gatewayAddress = "::0";

StackElementPlugin parent = (StackElementPlugin)m_object._Property.Container;

//prompt user to delete VLANs on IPs that are stacked over ER
DialogResult confirmVlanDeref = DialogResult.None;
foreach (object child in m_object.childrenList)
{
    IpV4V6Plugin ipPlugin = child as IpV4V6Plugin;
    if (ipPlugin == null)
    {
        continue;
    }    
    foreach (IpV4V6Range range in ipPlugin.rangeList)
    {
        if (range.vlanRange == null)
        {
            continue;
        }
        if (confirmVlanDeref == DialogResult.None)
        {
            confirmVlanDeref = MessageBox.Show(
                "VLANs cannot be created by plugins stacked over Emulated Router." + 
                "\nDo you want to de-reference VLAN ranges used by these plugins?",
                "VLAN Ranges",
                MessageBoxButtons.YesNo);
        }        
        if (confirmVlanDeref == DialogResult.Yes)
        {
            range.vlanRange = null;
        }        
        if (confirmVlanDeref == DialogResult.No)
        {
            break;
        }
    }    
    if (confirmVlanDeref == DialogResult.No)
    {
        break;
    }
}

while (parent != null)
{
    if (parent is HardwarePlugin)
    {
        break;
    }
    else if (parent is EmulatedRouterPlugin)
    {
        break;
    }
    parent = (StackElementPlugin)parent._Property.Container;
}

if (!(parent is EthernetPlugin) && !(parent is ATMPlugin) && !(parent is EmulatedRouterPlugin)) 
{
    return;
}

m_form.rangeListGrid.BeginUpdate();
m_form.rangeListGrid.MainView.BeginUpdate();

for(int i = 0; i < m_form.rangeListGrid.Columns.Count; i++)
{
    DevExpress.XtraGrid.Columns.GridColumn col= m_form.rangeListGrid.Columns[i];
    col.VisibleIndex=i;

    if(parent is ATMPlugin)
    {
        if(col.FieldName == "vlanRange" || 
          col.FieldName == "macRange" ||
          col.FieldName == "autoMacGeneration")
            col.VisibleIndex = -1;
    }
    else if (parent is EthernetPlugin)
    {
        if(col.FieldName == "atmRange" || col.FieldName == "pvcRange")
            col.VisibleIndex = -1;
    }
    else if(parent is EmulatedRouterPlugin)
    {
        if (col.FieldName == "vlanRange" || col.FieldName == "gatewayAddress" ||
           col.FieldName == "macRange" ||  col.FieldName == "generateStatistics" ||
           col.FieldName == "atmRange" || col.FieldName == "pvcRange" ||
          col.FieldName == "autoMacGeneration")
        {
            col.VisibleIndex = -1;
        }
    }
}

/*
 * autoMacGeneration must be true only for ethernet stacks.
 */
EthernetPlugin ethernetPlugin =
    m_object.GetAncestor(typeof(EthernetPlugin)) as EthernetPlugin;
if (ethernetPlugin == null)
{
    foreach(IpV4V6Range range in m_object.rangeList)
    {
        range.autoMacGeneration = false;
    }
}

m_form.rangeListGrid.EndUpdate();
m_form.rangeListGrid.MainView.EndUpdate();

aptixia.sm.DynamicGridControlEvent ev = i_arg1;
string error = "";
IpV4V6Range range = null;

try
{
    range = (IpV4V6Range) ev.DataList[ev.RowIndex];
}
catch
{
}

if (range != null)
{
    try
    {
        //the address constructor will throw an exception if the address is invalid    
        if (ev.FieldName == "ipAddress")
        {
            INetAddress address = AddressFactory.CreateAddress(ev.Data.ToString());
            if ( address.TypeString() != range.ipType)
                error += "Protocol does not match address\n";
        }

        if (ev.FieldName == "gatewayAddress")
        {
            string newVal = ((string)ev.Data).Trim();
            if(newVal == String.Empty || newVal == "0" || newVal == "0.0.0.0" || newVal == "::0")
            {
                if(range.ipType == "IPv6")
                    range.gatewayAddress = "::0";
                else
                    range.gatewayAddress = "0.0.0.0";
            }
            else
            {
                INetAddress gateway = AddressFactory.CreateAddress(ev.Data.ToString());
                if ( gateway.TypeString() != range.ipType)
                    error += "Gateway address doesn't match protocol type\n";
            }
        }

        if (ev.FieldName == "incrementBy")
        {
            INetAddress increment = AddressFactory.CreateAddress(ev.Data.ToString());
            if ( increment.TypeString() != range.ipType)
                error += "Increment doesn't match protocol type\n";
        }

        if (ev.FieldName == "count")
        {
            INetAddress address = AddressFactory.CreateAddress(range.ipAddress);
            ulong maxhosts = address.HostCountInMask((ulong)range.prefix);
            ulong count = UInt64.Parse(ev.Data.ToString());
            if (count > maxhosts)
                error += string.Format("Count too high. Mask {0} can only provide {1} addresses", 
                    range.prefix, maxhosts);
        }
    }
    catch(Exception e)
    {
        error += e.Message;
    }
}

/*
 * MAC range handlers
 */
MacRange macRange = null;

try
{
    macRange = (MacRange) ev.DataList[ev.RowIndex];
}
catch
{
}

if (macRange != null)
{
    if (ev.FieldName == "mac")
    {
        error += Verifier.VerifyMacAddress(ev.Data.ToString());
    }
    if (ev.FieldName == "incrementBy")
    {
        error += Verifier.VerifyMacAddress(ev.Data.ToString());
    }
}


ev.Error = error;

//OnSelectedRowDataChanged

aptixia.sm.DynamicGridControlEvent ev = i_arg1;

/*
 * IP range handlers
 */

IpV4V6Range range = null;
try
{
    range = (IpV4V6Range) ev.DataList[ev.RowIndex];
}
catch
{
}

if (range != null &&
    ev.FieldName == "autoMacGeneration" &&
    (bool)ev.Data == true)
{
    range.macRange = null;
}
if (range != null &&
    ev.FieldName == "ipType" &&
    range.ipType == "IPv6")
{
    range.gatewayAddress = "::0";
}


/*
 * VLAN range handlers
 */

VlanIdRange vlanRange = null;
try
{
    vlanRange = (VlanIdRange) ev.DataList[ev.RowIndex];
}
catch
{
}

if (vlanRange != null &&
    ev.FieldName == "innerEnable" &&
    vlanRange.innerEnable == true)
{
    vlanRange.enable = true;
}
if (vlanRange != null &&
    ev.FieldName == "enable" &&
    vlanRange.enable == false)
{
    vlanRange.innerEnable = false;
}
